module concat_8bit (
  input clk,
  input reset,
  input [7:0] a,
  input [7:0] b,
  input ctrl,
  output [15:0] out
);

reg [15:0] concat_result;

always @ (posedge clk or posedge reset) begin
  if (reset) begin
    concat_result <= 16'b0;
  end else begin
    if (ctrl) begin
      concat_result <= {a, b};
    end else begin
      concat_result <= {b, a};
    end
  end
end

assign out = concat_result;

endmodule
